#!/usr/bin/env bash
# Redwall firewall - one-shot installer for Hyprland + Caelestia.
# Self-contained: embeds the UI + system files, wires the bar/shell, then runs
# the privileged system install (nftables + NFQUEUE daemon + systemd service).
#   bash redwall-bootstrap.sh   (or: curl -fsSLO <url>/redwall-bootstrap.sh && bash redwall-bootstrap.sh)
set -euo pipefail
CAEL="${CAEL:-$HOME/.config/quickshell/caelestia}"
SHELLJSON="${SHELLJSON:-$HOME/.config/caelestia/shell.json}"
[ -d "$CAEL" ] || { echo "Caelestia config not found at $CAEL. Set CAEL=/path and retry."; exit 1; }
echo ">> Installing Redwall UI into $CAEL"
write() { mkdir -p "$(dirname "$1")"; base64 -d > "$1"; }

write "$CAEL/services/Firewall.qml" <<'B64'

B64
write "$CAEL/modules/bar/components/FirewallButton.qml" <<'B64'

B64
write "$CAEL/modules/firewall/FirewallPrompt.qml" <<'B64'

B64
write "$CAEL/modules/firewall/FirewallPanel.qml" <<'B64'

B64
write "$CAEL/system/redwall/redwalld.py" <<'B64'

B64
write "$CAEL/system/redwall/redwall.nft" <<'B64'

B64
write "$CAEL/system/redwall/redwalld.service" <<'B64'

B64
write "$CAEL/system/redwall/install.sh" <<'B64'

B64
write "$CAEL/system/redwall/uninstall.sh" <<'B64'

B64
write "$CAEL/system/redwall/README.md" <<'B64'

B64

chmod +x "$CAEL/system/redwall/redwalld.py" "$CAEL/system/redwall/install.sh" "$CAEL/system/redwall/uninstall.sh" "$CAEL/system/redwall/redwall.nft"
echo ">> Wiring bar + shell (idempotent; backs up as *.redwall-bak)"
python3 - "$CAEL" "$SHELLJSON" <<'PYEOF'
import json, re, sys, pathlib
cael = pathlib.Path(sys.argv[1]); shelljson = pathlib.Path(sys.argv[2])
def backup(p):
    b = p.with_suffix(p.suffix + ".redwall-bak")
    if p.exists() and not b.exists(): b.write_bytes(p.read_bytes())

sq = cael/"shell.qml"
if sq.exists():
    s = sq.read_text()
    if "modules/firewall" not in s:
        backup(sq)
        if 'import "modules/lock"' in s:
            s = s.replace('import "modules/lock"', 'import "modules/lock"\nimport "modules/firewall"', 1)
        else:
            s = re.sub(r'(\nimport [^\n]+\n)', r'\1import "modules/firewall"\n', s, count=1)
        if "ConfigToasts {}" in s:
            s = s.replace("ConfigToasts {}", "FirewallPrompt {}\n    FirewallPanel {}\n\n    ConfigToasts {}", 1)
        else:
            s = s.rstrip()[:-1] + "    FirewallPrompt {}\n    FirewallPanel {}\n}\n"
        sq.write_text(s); print("  patched shell.qml")
    else: print("  shell.qml already wired")
else: print("  !! shell.qml missing")

bq = cael/"modules/bar/Bar.qml"
if bq.exists():
    b = bq.read_text()
    if 'roleValue: "firewall"' not in b:
        backup(bq)
        choice = ('            DelegateChoice {\n'
                  '                roleValue: "firewall"\n'
                  '                delegate: EntryWrapper {\n'
                  '                    FirewallButton {\n'
                  '                        objectName: "taskbarFirewall"\n'
                  '                    }\n'
                  '                }\n'
                  '            }\n')
        m = re.search(r'[ \t]*DelegateChoice \{\s*\n\s*roleValue: "tray"', b)
        if m:
            b = b[:m.start()] + choice + b[m.start():]; bq.write_text(b); print("  patched Bar.qml")
        else:
            print("  !! Bar.qml: no tray delegate found - add the firewall DelegateChoice by hand")
    else: print("  Bar.qml already wired")
else: print("  !! Bar.qml missing")

try: cfg = json.loads(shelljson.read_text()) if shelljson.exists() else {}
except Exception: cfg = {}
bar = cfg.setdefault("bar", {}); entries = bar.get("entries")
default = ["logo","workspaces","spacer","activeWindow","spacer","tray","clock","statusIcons","power"]
ids = [(e.get("id") if isinstance(e, dict) else e) for e in entries] if entries else list(default)
if "firewall" not in ids:
    ids.insert(ids.index("tray") if "tray" in ids else len(ids), "firewall")
    bar["entries"] = [{"id": i} for i in ids]
    if shelljson.exists(): backup(shelljson)
    shelljson.parent.mkdir(parents=True, exist_ok=True)
    shelljson.write_text(json.dumps(cfg, indent=4)); print("  patched shell.json (bar entries)")
else: print("  shell.json already has firewall entry")
PYEOF

echo ">> Running privileged system install (sudo)"
sudo "$CAEL/system/redwall/install.sh"
echo ">> Reloading the shell"
caelestia shell -k >/dev/null 2>&1 || true; sleep 1; caelestia shell -d >/dev/null 2>&1 || true
echo; echo "Redwall installed. Red shield appears next to the tray; new apps now prompt."
